from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Mock database of valid tokens
valid_tokens = {
    'abc123': {'user_id': 1, 'scope': 'read'},
    'def456': {'user_id': 2, 'scope': 'write'}
}

def require_oauth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({'error': 'Missing token'}), 401
        
        token = token.split()[-1]
        if token in valid_tokens:
            return f(*args, **kwargs)
        else:
            return jsonify({'error': 'Invalid token'}), 403
    return decorated

@app.route('/api/data', methods=['GET'])
@require_oauth
def get_data():
    user_id = valid_tokens[request.headers.get('Authorization').split()[-1]]['user_id']
    data = {'user_id': user_id, 'data': 'some sensitive data'}
    return jsonify(data)

